import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { 
  CreditCard, Users, AlertTriangle, TrendingUp, 
  Calendar, ShoppingCart, DollarSign, Target, CheckCircle2,
  ArrowUpRight, Clock
} from 'lucide-react';

const Dashboard = () => {
  const [stats, setStats] = useState({
    totalMes: 0,
    totalEmAbertoFuturo: 0,
    parcelasFuturas: 0,
    maiorParcelaMes: 0,
    totalGeral: 0,
    qtdComprasMes: 0,
    detalhesPorPessoa: {}
  });
  const [perfil, setPerfil] = useState({ tipo: 'comum' });
  const [loading, setLoading] = useState(true);

  const hoje = new Date();
  const mesAtual = hoje.getMonth();
  const anoAtual = hoje.getFullYear();

  const colors = {
    primary: '#4361ee',
    secondary: '#7209b7',
    accent1: '#f72585',
    accent2: '#4cc9f0',
    success: '#00cc66',
    warning: '#ff9800',
    bg: '#f8fafc'
  };

  useEffect(() => {
    carregarDados();
  }, []);

  async function carregarDados() {
    setLoading(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return;

      // 1. Identificar o tipo de usuário
      const { data: perfilData } = await supabase
        .from('profiles')
        .select('tipo_usuario')
        .eq('id', user.id)
        .single();
      
      setPerfil(perfilData);

      // 2. Lógica de Permissão Master (Gleidson ou Proprietário)
      const isMaster = user.email === 'gleidson.fig@gmail.com';
      const isProprietario = perfilData?.tipo_usuario === 'proprietario';

      let query = supabase.from('compras').select('*, profiles(nome)');

      // Se não for admin/proprietário, filtra apenas os próprios dados
      if (!isMaster && !isProprietario) {
        query = query.eq('user_id', user.id);
      }

      const { data, error } = await query;
      if (error) throw error;

      // Debug para ver o que o banco está enviando (olhar o F12)
      // console.log("Dados recebidos:", data);

      let resumo = {
        totalMes: 0, totalEmAbertoFuturo: 0, parcelasFuturas: 0,
        maiorParcelaMes: 0, totalGeral: 0, qtdComprasMes: 0,
        detalhesPorPessoa: {}
      };

      data.forEach(item => {
        const valorTotal = parseFloat(item.valor_total) || 0;
        const numParcelas = parseInt(item.num_parcelas) || 1;
        const valorParcela = valorTotal / numParcelas;
        
        const [anoC, mesC, diaC] = item.data_compra.split('-');
        
        // CORREÇÃO DO "INDEFINIDO": 
        // Se o join com profiles falhar, usamos o ID ou um fallback amigável
        const responsavel = item.profiles?.nome || `Usuário (${item.user_id.substring(0, 4)})`;

        if (!resumo.detalhesPorPessoa[responsavel]) {
          resumo.detalhesPorPessoa[responsavel] = {
            totalRestanteFuturo: 0,
            valorNoMes: 0,
            qtdComprasMes: 0,
            ultimaParcelaDate: new Date(0),
            qtdTotalCompras: 0
          };
        }

        const p = resumo.detalhesPorPessoa[responsavel];
        resumo.totalGeral += valorTotal;
        p.qtdTotalCompras += 1;

        for (let i = 0; i < numParcelas; i++) {
          const dataParcela = new Date(anoC, (parseInt(mesC) - 1) + i, 1);
          
          if (dataParcela > p.ultimaParcelaDate) p.ultimaParcelaDate = dataParcela;

          if (dataParcela.getMonth() === mesAtual && dataParcela.getFullYear() === anoAtual) {
            resumo.totalMes += valorParcela;
            resumo.qtdComprasMes++;
            p.valorNoMes += valorParcela;
            p.qtdComprasMes++;
            if (valorParcela > resumo.maiorParcelaMes) resumo.maiorParcelaMes = valorParcela;
          }

          const proximoMes = new Date(anoAtual, mesAtual + 1, 1);
          if (dataParcela >= proximoMes) {
            resumo.totalEmAbertoFuturo += valorParcela;
            resumo.parcelasFuturas++;
            p.totalRestanteFuturo += valorParcela;
          }
        }
      });

      setStats(resumo);
    } catch (err) {
      console.error("Erro Dashboard:", err);
    } finally {
      setLoading(false);
    }
  }

  const formatMoney = (v) => `R$ ${v.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;

  if (loading) return <div style={{ padding: '50px', textAlign: 'center', fontWeight: 'bold', color: colors.primary }}>Carregando Dashboard...</div>;

  const isGlobalView = perfil?.tipo_usuario === 'proprietario' || stats.totalGeral > 0;

  return (
    <div className="fade-in" style={{ padding: '30px', backgroundColor: colors.bg, minHeight: '100vh', fontFamily: "'Inter', sans-serif", paddingBottom: '100px' }}>
      
      <div style={{ marginBottom: '35px' }}>
        <h2 style={{ margin: 0, fontSize: '1.8rem', fontWeight: 800, color: '#1e293b', letterSpacing: '-0.5px' }}>
          {perfil?.tipo_usuario === 'proprietario' ? 'Dashboard Financeiro Global' : 'Meu Resumo Financeiro'}
        </h2>
        <p style={{ color: '#64748b', marginTop: '5px' }}>
          {perfil?.tipo_usuario === 'proprietario' 
            ? 'Visão consolidada de todos os gastos da casa.' 
            : 'Controle de seus gastos pessoais e parcelas futuras.'}
        </p>
      </div>

      <div style={gridStyle}>
        <Card 
          title={perfil?.tipo_usuario === 'proprietario' ? "Fatura Total Mes" : "Minha Fatura Mes"} 
          icon={<Calendar size={20} />} 
          value={formatMoney(stats.totalMes)} 
          gradient={`linear-gradient(135deg, ${colors.primary}, #3f37c9)`} 
        />
        <Card 
          title="Dívida Futura" 
          icon={<Clock size={20} />} 
          value={formatMoney(stats.totalEmAbertoFuturo)} 
          gradient={`linear-gradient(135deg, ${colors.secondary}, #560bad)`} 
          footer="Total acumulado pós-fatura atual"
        />
        <Card 
          title="Parcelas no Mês" 
          icon={<ShoppingCart size={20} />} 
          value={stats.qtdComprasMes} 
          gradient={`linear-gradient(135deg, ${colors.accent2}, ${colors.primary})`}
        />
        <Card 
          title="Maior Parcela" 
          icon={<AlertTriangle size={20} />} 
          value={formatMoney(stats.maiorParcelaMes)} 
          gradient={`linear-gradient(135deg, ${colors.warning}, #f59e0b)`}
        />
      </div>

      <div style={{ margin: '50px 0 25px 0' }}>
        <h3 style={{ margin: 0, display: 'flex', alignItems: 'center', gap: '10px', color: '#1e293b', fontWeight: 700 }}>
          <Users size={24} color={colors.secondary} /> 
          {perfil?.tipo_usuario === 'proprietario' ? 'Resumo por Responsável' : 'Detalhamento Pessoal'}
        </h3>
      </div>

      <div style={gridStyle}>
        {Object.entries(stats.detalhesPorPessoa)
          .sort((a, b) => b[1].valorNoMes - a[1].valorNoMes)
          .map(([nome, dados]) => {
            const quitacaoFormatada = dados.ultimaParcelaDate.toLocaleDateString('pt-BR', { month: 'short', year: '2-digit' });

            return (
              <div key={nome} style={personCardStyle}>
                <div style={cardHeaderStyle}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <div style={{ background: `${colors.primary}10`, color: colors.primary, padding: '6px 14px', borderRadius: '12px', fontSize: '0.75rem', fontWeight: 800 }}>
                      {nome}
                    </div>
                    <ArrowUpRight size={18} color="#cbd5e1" />
                  </div>
                </div>

                <div style={{ marginBottom: '20px' }}>
                  <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                    <div>
                      <span style={labelStyle}>Total neste mês</span>
                      <div style={{ fontSize: '1.6rem', fontWeight: 800, color: '#1e293b' }}>{formatMoney(dados.valorNoMes)}</div>
                    </div>
                    
                    <div style={{ padding: '15px', background: '#f8fafc', borderRadius: '16px', border: '1px solid #f1f5f9' }}>
                      <span style={labelStyle}>Restante pós-fatura</span>
                      <div style={{ fontSize: '1.1rem', fontWeight: 700, color: colors.secondary }}>{formatMoney(dados.totalRestanteFuturo)}</div>
                    </div>
                  </div>
                </div>

                <div style={innerGridStyle}>
                  <MiniStat 
                    label="Itens Mês" 
                    value={dados.qtdComprasMes} 
                    icon={<ShoppingCart size={14} />} 
                    iconColor={colors.accent1}
                  />
                  <MiniStat 
                    label="Fim da Dívida" 
                    value={quitacaoFormatada} 
                    icon={<CheckCircle2 size={14} />} 
                    iconColor={colors.success}
                  />
                </div>
              </div>
            );
          })}
      </div>
    </div>
  );
};

/* COMPONENTES DE APOIO */
const Card = ({ title, icon, value, gradient, footer }) => (
  <div style={{
    padding: '24px',
    borderRadius: '24px',
    background: gradient,
    color: 'white',
    boxShadow: '0 10px 20px -5px rgba(0,0,0,0.1)',
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'space-between',
    minHeight: '135px',
    position: 'relative',
    overflow: 'hidden'
  }}>
    <div style={{ position: 'absolute', right: '-5%', top: '-5%', opacity: 0.15 }}>
      {React.cloneElement(icon, { size: 90 })}
    </div>
    <div style={{ display: 'flex', alignItems: 'center', gap: '8px', fontSize: '0.75rem', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.5px' }}>
      {icon} {title}
    </div>
    <div>
      <div style={{ fontSize: '1.7rem', fontWeight: 800, zIndex: 1, position: 'relative' }}>{value}</div>
      {footer && <div style={{ fontSize: '0.65rem', opacity: 0.8, marginTop: '4px' }}>{footer}</div>}
    </div>
  </div>
);

const MiniStat = ({ label, value, icon, iconColor }) => (
  <div style={{ 
    padding: '12px', 
    backgroundColor: 'white', 
    borderRadius: '12px',
    border: '1px solid #f1f5f9',
    display: 'flex',
    flexDirection: 'column',
    gap: '3px'
  }}>
    <div style={{ fontSize: '0.6rem', color: '#94a3b8', fontWeight: 700, display: 'flex', alignItems: 'center', gap: '5px', textTransform: 'uppercase' }}>
      <span style={{color: iconColor}}>{icon}</span> {label}
    </div>
    <div style={{ fontSize: '0.9rem', fontWeight: 700, color: '#334155' }}>
      {value}
    </div>
  </div>
);

/* ESTILOS */
const gridStyle = {
  display: 'grid',
  gridTemplateColumns: 'repeat(auto-fit, minmax(260px, 1fr))',
  gap: '20px'
};

const innerGridStyle = {
  display: 'grid',
  gridTemplateColumns: '1fr 1fr',
  gap: '10px'
};

const personCardStyle = {
  backgroundColor: 'white',
  padding: '24px',
  borderRadius: '24px',
  boxShadow: '0 4px 6px -1px rgba(0,0,0,0.02), 0 10px 15px -3px rgba(0,0,0,0.05)',
  border: '1px solid #f1f5f9'
};

const cardHeaderStyle = {
  marginBottom: '20px'
};

const labelStyle = {
  fontSize: '0.65rem', 
  fontWeight: 700, 
  color: '#94a3b8', 
  textTransform: 'uppercase', 
  letterSpacing: '0.8px',
  display: 'block',
  marginBottom: '2px'
};

export default Dashboard;
